    "animationLevel": "high",
    "html": "<div class=\"loader\"></div>",
    "css": "/* From Uiverse.io by FWDJc - Tags: animated, colorful, dvd, keyframes, css animation */\n.loader {\n  width: 150px;\n  height: 40px;\n  border-radius: 50%;\n  position: relative;\n  animation: bounce 5s infinite;\n}\n\n.loader::before {\n  content: 'DVD';\n  position: absolute;\n  display: block;\n  left: 5%;\n  bottom: 55%;\n  color: green;\n  font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Open Sans', 'Helvetica Neue', sans-serif;\n  font-size: 4em;\n  font-weight: 900;\n  font-style: italic;\n  animation: div-color-change 5s infinite;\n}\n\n.loader::after {\n  content: 'FWDJC';\n  position: absolute;\n  top: 30%;\n  left: 21%;\n  color: #212121;\n  font-size: .5em;\n  font-weight: 800;\n  letter-spacing: 10px;\n  z-index: 1;\n}\n\n@keyframes bounce {\n  0% {\n    background-color: red;\n    transform: translateX(0) translateY(60px);\n  }\n\n  25% {\n    background-color: blue;\n    transform: translateX(60px) translateY(0);\n  }\n\n  55% {\n    background-color: green;\n    transform: translateX(0) translateY(-60px);\n  }\n\n  75% {\n    background-color: yellow;\n    transform: translateX(-60px) translateY(0);\n  }\n\n  100% {\n    background-color: purple;\n    transform: translateX(0) translateY(60px);\n  }\n}\n\n@keyframes div-color-change {\n  0% {\n    color: red;\n  }\n\n  25% {\n    color: blue;\n  }\n\n  55% {\n    color: green;\n  }\n\n  75% {\n    color: yellow;\n  }\n\n  100% {\n    color: purple;\n  }\n}"
