    "html": "<div class=\"spinner\">\n<div class=\"dot1\"></div>\n<div class=\"dot2\"></div>\n<div class=\"dot3\"></div>\n</div>",
    "css": "/* From Uiverse.io by Mike11jr - Tags: loader */\n.spinner {\n flex-direction: row;\n display: flex;\n align-items: center;\n justify-content: center;\n}\n\n.dot1, .dot2, .dot3 {\n width: 15px;\n height: 15px;\n border: double;\n border-color: white;\n border-radius: 50%;\n margin: 10px;\n}\n\n.dot1 {\n animation: jump765 1.6s -0.32s linear infinite;\n background: #2495ff;\n}\n\n.dot2 {\n animation: jump765 1.6s -0.16s linear infinite;\n background: #2495ff;\n}\n\n.dot3 {\n animation: jump765 1.6s linear infinite;\n background: #2495ff;\n}\n\n@keyframes jump765 {\n 0%, 80%, 100% {\n  -webkit-transform: scale(0);\n  transform: scale(0);\n }\n\n 40% {\n  -webkit-transform: scale(2.0);\n  transform: scale(2.0);\n }\n}"
