    "css": "/* From Uiverse.io by MyNameJeremy - Tags: loader */\n.neomorph-spinner {\n  position: relative;\n  width: 80px;\n  height: 80px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  border-radius: 50%;\n  margin: auto;\n  box-shadow: 0 2px 10px 0 rgba(0, 0, 0, 0.3);\n}\n\n.neomorph-spinner > div {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  border-radius: 50%;\n  background-color: #004dff;\n  box-shadow: 0 2px 10px 0 rgba(0, 0, 0, 0.3);\n  animation: spin_5113 1s ease infinite;\n}\n\n.neomorph-spinner > div:nth-child(1) {\n  transform: rotate(0deg);\n}\n\n.neomorph-spinner > div:nth-child(2) {\n  transform: rotate(90deg);\n}\n\n.neomorph-spinner > div:nth-child(3) {\n  transform: rotate(180deg);\n}\n\n.neomorph-spinner > div:nth-child(4) {\n  transform: rotate(270deg);\n}\n\n@keyframes spin_5113 {\n  0% {\n    opacity: 1;\n  }\n\n  100% {\n    opacity: 0;\n  }\n}"
