    "animationLevel": "high",
    "html": "<div class=\"loading\">\n  <div class=\"side front\"></div>\n  <div class=\"side back\"></div>\n  <div class=\"side top\"></div>\n  <div class=\"side bottom\"></div>\n  <div class=\"side left\"></div>\n  <div class=\"side right\"></div>\n</div>",
    "css": "/* From Uiverse.io by Nawsome - Tags: loader */\n.loading {\n  width: 100px;\n  height: 100px;\n  background: white;\n  border-radius: 12px;\n  position: relative;\n  transform-style: preserve-3d;\n  animation: loading_4123 2s linear infinite;\n}\n\n.side {\n  background: white;\n  border-radius: 12px;\n}\n\n.front, .back {\n  width: 100px;\n  height: 100px;\n}\n\n.front, .back {\n  position: absolute;\n  left: 0;\n  right: 0;\n  top: 0;\n  bottom: 0;\n}\n\n.back {\n  transform: translateZ(-10px);\n}\n\n.left, .right {\n  width: 10px;\n  height: calc(100% - 12px);\n  top: 6px;\n  position: absolute;\n  background: #efefef;\n}\n\n.left {\n  left: 0;\n  transform-origin: 0;\n  transform: rotateY(90deg);\n}\n\n.right {\n  right: 0;\n  transform-origin: 100%;\n  transform: rotateY(-90deg);\n}\n\n.top, .bottom {\n  width: calc(100% - 12px);\n  height: 10px;\n  position: absolute;\n  left: 6px;\n  background: #efefef;\n}\n\n.top {\n  top: -10px;\n  transform-origin: 0 100%;\n  transform: rotateX(90deg);\n}\n\n.bottom {\n  bottom: -10px;\n  transform-origin: 0 0;\n  transform: rotateX(-90deg);\n}\n\n@keyframes loading_4123 {\n  0% {\n    transform: rotate(0);\n  }\n\n  50% {\n    transform: rotateY(180deg);\n  }\n\n  100% {\n    transform: rotateY(180deg) rotateX(-180deg);\n  }\n}"
