    "html": "<div class=\"container\">\n\t<div class=\"loader\"></div>\n\t<div class=\"loader\"></div>\n\t<div class=\"loader\"></div>\n</div>",
    "css": "/* From Uiverse.io by Nawsome - Tags: loader */\n.loader {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  z-index: 10;\n  width: 160px;\n  height: 100px;\n  margin-left: -80px;\n  margin-top: -50px;\n  border-radius: 5px;\n  background: #1e3f57;\n  animation: dot1_ 3s cubic-bezier(0.55,0.3,0.24,0.99) infinite;\n}\n\n.loader:nth-child(2) {\n  z-index: 11;\n  width: 150px;\n  height: 90px;\n  margin-top: -45px;\n  margin-left: -75px;\n  border-radius: 3px;\n  background: #3c517d;\n  animation-name: dot2_;\n}\n\n.loader:nth-child(3) {\n  z-index: 12;\n  width: 40px;\n  height: 20px;\n  margin-top: 50px;\n  margin-left: -20px;\n  border-radius: 0 0 5px 5px;\n  background: #6bb2cd;\n  animation-name: dot3_;\n}\n\n@keyframes dot1_ {\n  3%,97% {\n    width: 160px;\n    height: 100px;\n    margin-top: -50px;\n    margin-left: -80px;\n  }\n\n  30%,36% {\n    width: 80px;\n    height: 120px;\n    margin-top: -60px;\n    margin-left: -40px;\n  }\n\n  63%,69% {\n    width: 40px;\n    height: 80px;\n    margin-top: -40px;\n    margin-left: -20px;\n  }\n}\n\n@keyframes dot2_ {\n  3%,97% {\n    height: 90px;\n    width: 150px;\n    margin-left: -75px;\n    margin-top: -45px;\n  }\n\n  30%,36% {\n    width: 70px;\n    height: 96px;\n    margin-left: -35px;\n    margin-top: -48px;\n  }\n\n  63%,69% {\n    width: 32px;\n    height: 60px;\n    margin-left: -16px;\n    margin-top: -30px;\n  }\n}\n\n@keyframes dot3_ {\n  3%,97% {\n    height: 20px;\n    width: 40px;\n    margin-left: -20px;\n    margin-top: 50px;\n  }\n\n  30%,36% {\n    width: 8px;\n    height: 8px;\n    margin-left: -5px;\n    margin-top: 49px;\n    border-radius: 8px;\n  }\n\n  63%,69% {\n    width: 16px;\n    height: 4px;\n    margin-left: -8px;\n    margin-top: -37px;\n    border-radius: 10px;\n  }\n}"
