    "css": "/* From Uiverse.io by Praashoo7 - Tags: animation, loader, dots */\n.load {\n  display: flex;\n  border-radius: 50%;\n  flex-direction: row;\n}\n\n.progress {\n  width: 2em;\n  height: 2em;\n  margin: 0.4em;\n  scale: 0;\n  border-radius: 50%;\n  background: rgb(255, 255, 255);\n  animation: loading_492 2s ease infinite;\n  animation-delay: 1s;\n}\n\n@keyframes loading_492 {\n  50% {\n    scale: 1;\n  }\n}\n\n.progress:nth-child(2) {\n  animation-delay: 1.3s;\n}\n\n.progress:nth-child(3) {\n  animation-delay: 1.7s;\n}"
