    "css": "/* From Uiverse.io by Praashoo7 - Tags: animation, loader */\n.loader2 {\n  display: flex;\n  align-items: center;\n}\n\n.load21 {\n  position: relative;\n  content: \"\";\n  height: 0.2em;\n  width: 4em;\n  border-radius: 5px;\n  opacity: 0;\n  background-color: white;\n  box-shadow: 0 1px 7px rgba(0,0,0,0.3);\n  animation: 2s flow_21 infinite;\n  animation-delay: 0.2s;\n}\n\n.load22 {\n  position: absolute;\n  content: \"\";\n  height: 0.2em;\n  width: 4em;\n  opacity: 0;\n  border-radius: 5px;\n  background-color: white;\n  animation: 2s flow_21 infinite;\n  animation-delay: 0.4s;\n}\n\n.load23 {\n  position: absolute;\n  content: \"\";\n  height: 0.2em;\n  width: 4em;\n  opacity: 0;\n  border-radius: 5px;\n  background-color: white;\n  animation: 2s flow_21 infinite;\n  animation-delay: 0.6s;\n}\n\n.load24 {\n  position: absolute;\n  content: \"\";\n  height: 0.2em;\n  width: 4em;\n  opacity: 0;\n  border-radius: 5px;\n  background-color: white;\n  animation: 2s flow_21 infinite;\n  animation-delay: 0.8s;\n}\n\n.load25 {\n  position: absolute;\n  content: \"\";\n  height: 0.2em;\n  width: 4em;\n  opacity: 0;\n  border-radius: 5px;\n  background-color: white;\n  animation: 2s flow_21 infinite;\n  animation-delay: 1s;\n}\n\n@keyframes flow_21 {\n  0% {\n    transform: translateY(1em);\n    opacity: 1;\n  }\n\n  50% {\n    transform: translateY(-1em);\n    opacity: 1;\n  }\n\n  100% {\n    transform: translateY(1em);\n    opacity: 1;\n  }\n}"
