    "css": "/* From Uiverse.io by Shoh2008 - Tags: loader */\n.loader {\n  width: 0;\n  height: 4.8px;\n  display: inline-block;\n  position: relative;\n  background: #FFF;\n  box-shadow: 0 0 10px rgba(255, 255, 255, 0.5);\n  box-sizing: border-box;\n  animation: animFw 8s linear infinite;\n}\n\n.loader::after,\n  .loader::before {\n  content: '';\n  width: 10px;\n  height: 1px;\n  background: #FFF;\n  position: absolute;\n  top: 9px;\n  right: -2px;\n  opacity: 0;\n  transform: rotate(-45deg) translateX(0px);\n  box-sizing: border-box;\n  animation: coli1 0.3s linear infinite;\n}\n\n.loader::before {\n  top: -4px;\n  transform: rotate(45deg);\n  animation: coli2 0.3s linear infinite;\n}\n\n@keyframes animFw {\n  0% {\n    width: 0;\n  }\n\n  100% {\n    width: 100%;\n  }\n}\n\n@keyframes coli1 {\n  0% {\n    transform: rotate(-45deg) translateX(0px);\n    opacity: 0.7;\n  }\n\n  100% {\n    transform: rotate(-45deg) translateX(-45px);\n    opacity: 0;\n  }\n}\n\n@keyframes coli2 {\n  0% {\n    transform: rotate(45deg) translateX(0px);\n    opacity: 1;\n  }\n\n  100% {\n    transform: rotate(45deg) translateX(-45px);\n    opacity: 0.7;\n  }\n}"
