    "css": "/* From Uiverse.io by Uncannypotato69  - Tags: simple, animation, white, black, loading, loader, text animation, css */\n.textWrapper {\n  height: fit-content;\n  min-width: 3rem;\n  width: fit-content;\n  font-size: 2rem;\n  font-weight: 700;\n  letter-spacing: 0.25ch;\n  position: relative;\n  z-index: 0;\n  color: white;\n}\n\n.invertbox {\n  position: absolute;\n  height: 100%;\n  aspect-ratio: 1/1;\n  left: 0;\n  top: 0;\n  border-radius: 20%;\n  background-color: rgba(255, 255, 255, 0.1);\n  backdrop-filter: invert(100%);\n  animation: move 2s ease-in-out infinite;\n}\n\n@keyframes move {\n  50% {\n    left: calc(100% - 3rem);\n  }\n}"
