    "css": "/* From Uiverse.io by Uncannypotato69  - Tags: simple, animation, loading, loader, text, css, loading animation */\n.wrapper {\n  min-height: 3rem;\n  min-width: 14rem;\n  font-size: 2rem;\n  position: relative;\n  overflow: hidden;\n  mask-image: linear-gradient(\n    to right,\n    rgba(0, 0, 0, 0),\n    rgba(0, 0, 0, 1) 30%,\n    rgba(0, 0, 0, 1) 70%,\n    rgba(0, 0, 0, 0)\n  );\n  font-family: monospace;\n}\n\n.letter {\n  width: 1ch;\n  position: absolute;\n  top: 50%;\n  transform: translate(0px, -50%);\n  left: 100%;\n  animation: scroll 2.5s linear infinite;\n}\n\n@keyframes scroll {\n  to {\n    left: -1ch;\n  }\n}\n\n.letter1 {\n  animation-delay: calc(2.5s / 10 * (10 - 1) * -1);\n}\n.letter2 {\n  animation-delay: calc(2.5s / 10 * (10 - 2) * -1);\n}\n.letter3 {\n  animation-delay: calc(2.5s / 10 * (10 - 3) * -1);\n}\n.letter4 {\n  animation-delay: calc(2.5s / 10 * (10 - 4) * -1);\n}\n.letter5 {\n  animation-delay: calc(2.5s / 10 * (10 - 5) * -1);\n}\n.letter6 {\n  animation-delay: calc(2.5s / 10 * (10 - 6) * -1);\n}\n.letter7 {\n  animation-delay: calc(2.5s / 10 * (10 - 7) * -1);\n}\n.letter8 {\n  animation-delay: calc(2.5s / 10 * (10 - 8) * -1);\n}\n.letter9 {\n  animation-delay: calc(2.5s / 10 * (10 - 9) * -1);\n}\n.letter10 {\n  animation-delay: calc(2.5s / 10 * (10 - 10) * -1);\n}"
