    "html": "<div class=\"meteor\"></div>",
    "css": "/* From Uiverse.io by Z4drus  - Tags: simple, glassmorphism, minimalist, white, black, loading, loader, loading animation */\n@keyframes spin {\n  0% {\n    transform: rotateY(0deg) translateZ(0);\n  }\n  100% {\n    transform: rotateY(360deg) translateZ(0);\n  }\n}\n\nbody,\nhtml {\n  height: 100%;\n  margin: 0;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.meteor {\n  width: 150px;\n  height: 150px;\n  background: linear-gradient(\n    135deg,\n    rgba(255, 255, 255, 0.6) 0%,\n    rgba(0, 0, 0, 0.6) 100%\n  );\n  border-radius: 50%;\n  position: relative;\n  animation: spin 3s linear infinite;\n  box-shadow: 0 0 20px rgba(255, 255, 255, 0.5);\n  transform-style: preserve-3d;\n}\n\n.meteor::before,\n.meteor::after {\n  content: \"\";\n  position: absolute;\n  top: 0;\n  left: 0;\n  right: 0;\n  bottom: 0;\n  border-radius: 50%;\n  background: inherit;\n}\n\n.meteor::before {\n  transform: translateZ(-15px);\n}\n\n.meteor::after {\n  transform: translateZ(15px);\n}"
