    "css": "/* From Uiverse.io by aadium - Tags: loader, wheel, car */\n.loader {\n}\n\n.wheel {\n  fill: rgb(128, 128, 128);\n  font-size: 100px;\n  width: 100px;\n  height: 100px;\n  border-radius: 6em;\n  text-align: center;\n  animation: rolling 1s linear infinite;\n}\n\n#rim {\n  fill: rgb(126, 126, 126);\n}\n\n#tire {\n  fill: rgb(55, 55, 55);\n}\n\n.road {\n  position: absolute;\n  margin-top: -4px;\n  width: 100%;\n  height: 10px;\n  border-radius: 5em;\n  background-color: rgb(55, 55, 55);\n  animation: road-move 2s linear infinite;\n}\n\n@keyframes rolling {\n  to {\n    transform: rotate(-360deg);\n  }\n}\n\n@keyframes road-move {\n  from {\n    transform: translateX(-140%);\n  }\n\n  to {\n    transform: translateX(100%);\n  }\n}"
