    "css": "/* From Uiverse.io by akshat-patel28 - Tags: animation, loader, animated, box */\n.loader {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  gap: 30px;\n}\n\n.box-1,.box-2,.box-3 {\n  width: 1px;\n  height: 115px;\n  border: 1px solid #e9e9e9;\n  background-color: transparent;\n  box-sizing: border-box;\n}\n\n.box-1 {\n  animation: box1animation 4s  forwards ease-in-out infinite;\n}\n\n@keyframes box1animation {\n  0% {\n    width: 1px;\n  }\n\n  12.5% {\n    width: 60px;\n  }\n\n  25% {\n    width: 60px;\n  }\n\n  37.5% {\n    width: 1px;\n  }\n\n  50% {\n    width: 1px;\n  }\n\n  62.5% {\n    width: 1px;\n  }\n\n  75% {\n    width: 1px;\n  }\n\n  100% {\n    width: 1px;\n  }\n}\n\n.box-2 {\n  animation: box2animation 4s forwards ease-in-out infinite;\n}\n\n@keyframes box2animation {\n  0% {\n    width: 1px;\n  }\n\n  12.5% {\n    width: 1px;\n  }\n\n  25% {\n    width: 1px;\n  }\n\n  37.5% {\n    width: 60px;\n  }\n\n  50% {\n    width: 60px;\n  }\n\n  62.5% {\n    width: 1px;\n  }\n\n  75% {\n    width: 1px;\n  }\n\n  100% {\n    width: 1px;\n  }\n}\n\n.box-3 {\n  animation: box3animation 4s  forwards ease-in-out infinite;\n}\n\n@keyframes box3animation {\n  0% {\n    width: 1px;\n  }\n\n  12.5% {\n    width: 1px;\n  }\n\n  25% {\n    width: 1px;\n  }\n\n  37.5% {\n    width: 1px;\n  }\n\n  50% {\n    width: 1px;\n  }\n\n  62.5% {\n    width: 60px;\n  }\n\n  75% {\n    width: 60px;\n  }\n\n  100% {\n    width: 1px;\n  }\n}"
