    "css": "/* From Uiverse.io by ayman-ashine  - Tags: loader, animated, multicolor */\n.loader {\n  --c-1: #a2ff37;\n  --c-2: #5bb2ff;\n  position: relative;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n\n.layer {\n  font-size: 25px;\n  font-family: \"Segoe UI\", Tahoma;\n  font-weight: 800;\n  text-transform: uppercase;\n  position: absolute;\n}\n\n.layer:nth-child(1) {\n  color: var(--c-1);\n  animation: kfs-3412 0.5s infinite;\n}\n\n.layer:nth-child(2) {\n  color: var(--c-2);\n  animation: kfs-3412 0.5s 0.25s infinite;\n}\n\n@keyframes kfs-3412 {\n  0% {\n    text-shadow: 0 0 30px var(--c-1);\n    transform: scaleY(0);\n    z-index: 2;\n  }\n  50% {\n    transform: scaleY(1.5);\n    z-index: 2;\n  }\n  100% {\n    transform: scaleY(1.5);\n    z-index: 0;\n  }\n}"
