    "html": "<div class=\"loading-spinner\">\n  <div class=\"loading-spinner-inner\">\n    <div class=\"loading-spinner-circle\"></div>\n    <div class=\"loading-spinner-circle\"></div>\n    <div class=\"loading-spinner-circle\"></div>\n    <div class=\"loading-spinner-circle\"></div>\n    <div class=\"loading-spinner-circle\"></div>\n  </div>\n</div>",
    "css": "/* From Uiverse.io by coding-masala - Tags: loader */\n.loading-spinner {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  height: 8em;\n}\n\n.loading-spinner-inner {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.loading-spinner-circle {\n  width: 1em;\n  height: 1em;\n  border-radius: 50%;\n  background-color: #db9334;\n  margin: 0 5px;\n  animation: loading-spinner 1s ease-in-out infinite;\n}\n\n.loading-spinner-circle:nth-child(2) {\n  animation-delay: 0.2s;\n}\n\n.loading-spinner-circle:nth-child(3) {\n  animation-delay: 0.4s;\n}\n\n.loading-spinner-circle:nth-child(4) {\n  animation-delay: 0.6s;\n}\n\n.loading-spinner-circle:nth-child(5) {\n  animation-delay: 0.8s;\n}\n\n@keyframes loading-spinner {\n  0% {\n    transform: scale(1);\n    opacity: 1;\n  }\n\n  20% {\n    transform: scale(1.5);\n    opacity: 0.5;\n  }\n\n  100% {\n    transform: scale(1);\n    opacity: 1;\n  }\n}"
