    "html": "<div class=\"spinner\">\n<div class=\"loader l1\"></div>\n<div class=\"loader l2\"></div>\n</div>",
    "css": "/* From Uiverse.io by gagan-gv - Tags: loader */\n.spinner {\n border: 0 solid transparent;\n border-radius: 50%;\n width: 50px;\n height: 50px;\n}\n\n.loader {\n width: inherit;\n height: inherit;\n position: absolute;\n}\n\n.loader::before,\n.loader::after {\n content: '';\n border: 3px solid #505065;\n border-radius: 50%;\n width: inherit;\n height: inherit;\n position: absolute;\n opacity: 1;\n}\n\n.l1::before,\n.l1::after {\n animation: clockwiseZ 2.5s infinite;\n}\n\n.l2::after,\n.l2::before {\n animation: anticlockwiseZ 2.5s infinite;\n}\n\n@keyframes clockwiseZ {\n 0%, 100% {\n  transform: rotateY(0);\n }\n\n 50% {\n  transform: rotateY(180deg) skew(-10deg, -5deg);\n }\n}\n\n@keyframes anticlockwiseZ {\n 0%, 100% {\n  transform: rotateX(0);\n }\n\n 50% {\n  transform: rotateX(-180deg) skew(10deg, 5deg);\n }\n}"
