    "animationLevel": "high",
    "html": "<div class=\"sharingon\">\n  <div class=\"ring\">\n  <div class=\"to\"></div>\n<div class=\"to\"></div>\n<div class=\"to\"></div>\n<div class=\"circle\"></div>\n</div>\n</div>",
    "css": "/* From Uiverse.io by shadowfax29 - Source: shadowfax29 - Tags: circle loader, aesthetic, sharingon  */\n.sharingon {\n  width: 6em;\n  height: 6em;\n  background-color: red;\n  border: 6px solid black;\n  animation: rot 1s ease-in-out infinite;\n}\n\n.ring {\n  position: absolute;\n  content: \"\";\n  left: 50%;\n  top: 50%;\n  width: 3.5em;\n  height: 3.5em;\n  border: 4px solid rgb(110, 13 ,13 ,0.5);\n  transform: translate(-50%,-50%);\n}\n\n.sharingon, .ring, .to,.circle {\n  border-radius: 50%;\n}\n\n.to,.circle {\n  position: absolute;\n  content: \"\";\n  width: 0.9em;\n  height: 0.9em;\n  background-color: black;\n}\n\n.to:nth-child(1) {\n  top: -0.5em;\n  left: 50%;\n  transform: translate(-40%);\n}\n\n.to::before {\n  content: \"\";\n  position: absolute;\n  top: -0.5em;\n  right: -0.2em;\n  width: 1.1em;\n  height: 0.9em;\n  box-sizing: border-box;\n  border-left: 16px solid black;\n  border-radius: 100% 0 0;\n}\n\n.to:nth-child(2) {\n  bottom: 0.5em;\n  left: -0.35em;\n  transform: rotate(-120deg);\n}\n\n.to:nth-child(3) {\n  bottom: 0.5em;\n  right: -0.35em;\n  transform: rotate(120deg);\n}\n\n.circle {\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%,-50%);\n  box-shadow: 0 0 20px 1px;\n  width: 1em;\n  height: 1em;\n}\n\n@keyframes rot {\n  0% {\n    transform: rotate(0deg);\n  }\n\n  100% {\n    transform: rotate(360deg);\n  }\n}"
