    "html": "<div class=\"center-body\">\n  <div class=\"loader-circle-9\">\n    Loading\n    <span></span>\n  </div>\n</div>",
    "css": "/* From Uiverse.io by vikramsinghnegi  - Tags: loading, loader, effect loader */\n.center-body {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  width: 100%;\n  height: 100%;\n  background: #262626;\n}\n\n.loader-circle-9 {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n  width: 70px;\n  height: 70px;\n  background: transparent;\n  border: 3px solid #3c3c3c;\n  border-radius: 50%;\n  text-align: center;\n  line-height: 70px;\n  font-family: sans-serif;\n  font-size: 12px;\n  color: #00eaff;\n  text-transform: uppercase;\n  box-shadow: 0 0 20px rgba(0, 0, 0, 0.5);\n}\n\n.loader-circle-9:before {\n  content: \"\";\n  position: absolute;\n  top: -3px;\n  left: -3px;\n  width: 100%;\n  height: 100%;\n  border: 3px solid transparent;\n  border-top: 3px solid #00eaff;\n  border-right: 3px solid #00eaff;\n  border-radius: 50%;\n  animation: animateC 2s linear infinite;\n}\n\n.loader-circle-9 span {\n  display: block;\n  position: absolute;\n  top: calc(50% - 2px);\n  left: 50%;\n  width: 50%;\n  height: 4px;\n  background: transparent;\n  transform-origin: left;\n  animation: animate 2s linear infinite;\n}\n\n.loader-circle-9 span:before {\n  content: \"\";\n  position: absolute;\n  width: 16px;\n  height: 16px;\n  border-radius: 50%;\n  background: #00eaff;\n  top: -6px;\n  right: -8px;\n  box-shadow: 0 0 20px #00eaff;\n}\n\n@keyframes animateC {\n  0% {\n    transform: rotate(0deg);\n  }\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n@keyframes animate {\n  0% {\n    transform: rotate(45deg);\n  }\n  100% {\n    transform: rotate(405deg);\n  }\n}"
