    "animationLevel": "high",
    "html": "<div class=\"loader\">\n  <div class=\"wrapper\">\n    <div class=\"text\">LOADING</div>\n    <div class=\"box\"></div>\n  </div>\n</div>",
    "css": "/* From Uiverse.io by vinodjangid07  - Tags: animation, loading, loader, multicolor, loading animation */\n.loader {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n.wrapper {\n  width: 180px;\n  height: 50px;\n  position: relative;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  z-index: 2;\n}\n.text {\n  z-index: 3;\n  font-family: Whitney, -apple-system, Helvetica;\n  letter-spacing: 1px;\n  font-weight: 700;\n  font-size: 20px;\n  color: white;\n  filter: drop-shadow(2px 2px 0px #ff9e02);\n}\n.box {\n  width: 100%;\n  height: 100%;\n  background-color: #ef5d2e;\n  position: absolute;\n  z-index: 2;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  animation: loading ease-in-out 0.9s infinite alternate-reverse;\n}\n@keyframes loading {\n  0% {\n    transform: translateX(-20px);\n  }\n  100% {\n    transform: translateX(20px);\n  }\n}\n.box::before {\n  content: \"\";\n  width: 20px;\n  height: 170%;\n  background-color: #ff9d0089;\n  position: absolute;\n  z-index: 1;\n  animation: loading2 ease-in-out 0.9s infinite alternate-reverse;\n}\n@keyframes loading2 {\n  0% {\n    transform: translateX(-50px);\n  }\n  100% {\n    transform: translateX(50px);\n  }\n}"
