    "css": "/* From Uiverse.io by vinodjangid07  - Tags: animation, loading, loader */\n.loader {\n  width: fit-content;\n  height: fit-content;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n.wrapper {\n  width: fit-content;\n  height: fit-content;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n}\n.catContainer {\n  width: 100%;\n  height: fit-content;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  position: relative;\n}\n.catbody {\n  width: 80px;\n}\n.tail {\n  position: absolute;\n  width: 17px;\n  top: 50%;\n  animation: tail 0.5s ease-in infinite alternate-reverse;\n  transform-origin: top;\n}\n@keyframes tail {\n  0% {\n    transform: rotateZ(60deg);\n  }\n  50% {\n    transform: rotateZ(0deg);\n  }\n  100% {\n    transform: rotateZ(-20deg);\n  }\n}\n.wall {\n  width: 300px;\n}\n.text {\n  display: flex;\n  flex-direction: column;\n  width: 50px;\n  position: absolute;\n  margin: 0px 0px 100px 120px;\n}\n.zzz {\n  color: black;\n  font-weight: 700;\n  font-size: 15px;\n  animation: zzz 2s linear infinite;\n}\n.bigzzz {\n  color: black;\n  font-weight: 700;\n  font-size: 25px;\n  margin-left: 10px;\n  animation: zzz 2.3s linear infinite;\n}\n@keyframes zzz {\n  0% {\n    color: transparent;\n  }\n  50% {\n    color: black;\n  }\n  100% {\n    color: transparent;\n  }\n}"
