    "html": "<div id=\"container\">\n  <label class=\"loading-title\">Loading ...</label>\n  <span class=\"loading-circle sp1\">\n    <span class=\"loading-circle sp2\">\n      <span class=\"loading-circle sp3\"></span>\n    </span>\n  </span>\n</div>",
    "css": "/* From Uiverse.io by zanina-yassine - Tags: loader */\n#container {\n  width: 100px;\n  height: 125px;\n  margin: auto auto;\n}\n\n.loading-title {\n  display: block;\n  text-align: center;\n  font-size: 20;\n  font-family: 'Inter', sans-serif;\n  font-weight: bold;\n  padding-bottom: 15px;\n  color: #888;\n}\n\n.loading-circle {\n  display: block;\n  border-left: 5px solid;\n  border-top-left-radius: 100%;\n  border-top: 5px solid;\n  margin: 5px;\n  animation-name: Loader_611;\n  animation-duration: 1500ms;\n  animation-timing-function: linear;\n  animation-delay: 0s;\n  animation-iteration-count: infinite;\n  animation-direction: normal;\n  animation-fill-mode: forwards;\n}\n\n.sp1 {\n  border-left-color: #F44336;\n  border-top-color: #F44336;\n  width: 40px;\n  height: 40px;\n}\n\n.sp2 {\n  border-left-color: #FFC107;\n  border-top-color: #FFC107;\n  width: 30px;\n  height: 30px;\n}\n\n.sp3 {\n  width: 20px;\n  height: 20px;\n  border-left-color: #8bc34a;\n  border-top-color: #8bc34a;\n}\n\n@keyframes Loader_611 {\n  0% {\n    transform: rotate(0deg);\n    transform-origin: right bottom;\n  }\n\n  25% {\n    transform: rotate(90deg);\n    transform-origin: right bottom;\n  }\n\n  50% {\n    transform: rotate(180deg);\n    transform-origin: right bottom;\n  }\n\n  75% {\n    transform: rotate(270deg);\n    transform-origin: right bottom;\n  }\n\n  100% {\n    transform: rotate(360deg);\n    transform-origin: right bottom;\n  }\n}"
